const express = require('express');
const cors = require('cors');
const { execSync } = require('child_process');

const app = express();
app.use(cors());
app.use(express.json());

app.post('/convert', (req, res) => {
    const inputFile = req.body.inputFile;
    const outputFormat = req.body.outputFormat;
    const libreOfficeCommand = `libreoffice --headless --convert-to ${outputFormat} "${inputFile}"`;

    try {
        execSync(libreOfficeCommand, { stdio: 'inherit' });
        res.status(200).send('Conversion successful.');
    } catch (error) {
        console.error(`Error occurred during conversion: ${error}`);
        res.status(500).send(`Error occurred during conversion: ${error}`);
    }
});

